import sys
from lxml import etree, validity
from xml.sax.saxutils import escape

def validate_and_parse(xsd_file, xml_file):
    try:
        xsd = etree.XMLSchema(etree.parse(xsd_file))
        with open(xml_file, 'rb') as f:
            xml_data = f.read()
        doc = etree.fromstring(xml_data)
        xsd.validate(doc)
        return doc
    except (etree.XMLSyntaxError, validity.ValidatorError) as e:
        print("Error during validation:", escape(str(e)))
        sys.exit(1)

def main():
    if len(sys.argv) != 3:
        print("Usage: python script.py xsd_file xml_file")
        sys.exit(1)

    xsd_file = sys.argv[1]
    xml_file = sys.argv[2]

    parsed_xml = validate_and_parse(xsd_file, xml_file)
    print("XML document is valid and has been successfully parsed.")
    print("Parsed XML:")
    print(etree.tostring(parsed_xml, pretty_print=True).decode())

if __name__ == "__main__":
    main()